const msg=($input.first().json.chatInput||$input.first().json.input||'').trim();
if(msg.toLowerCase()==='list')return[{json:{mode:'list'}}];
const rem=msg.match(/^remove\s+([A-Z0-9]{6,8})$/i);
if(rem)return[{json:{mode:'remove',companyNumber:rem[1].toUpperCase()}}];
const parts=msg.match(/^add\s+([A-Z0-9]{6,8})\s+(\d{1,2})\s+(.+)$/i);
if(!parts)throw new Error('Format: add <regNo> <ranking 1-10> <products>  OR: remove <regNo>  OR: list');
const products=parts[3].split(',').map(function(p){return p.trim();}).filter(Boolean);
return[{json:{mode:'add',companyNumber:parts[1].toUpperCase(),ranking:Number(parts[2]),products:products}}];

const resp=$input.first().json;
const hdrs=resp.headers||{};
const s3Url=hdrs.location||hdrs.Location||null;
return[{json:{s3Url:s3Url}}];

const input=$('Parse Input').first().json;
const company=$('CH: Company').first().json;
const officers=$('CH: Officers').first().json;
const webData=$input.first().json;
let financials={turnover:null,employees:null,netAssets:null,accountsYear:null};
try{
  const finRaw=$('HTTP: Extract Financials').first().json;
  if(finRaw&&finRaw.response){
    const text=finRaw.response;
    try{
      const parsed=JSON.parse(text);
      financials={turnover:parsed.turnover||null,employees:parsed.employees||null,netAssets:parsed.netAssets||null,accountsYear:parsed.year||null};
    }catch(e){
      const lines=text.split(/\r?\n/);
      const getNum=function(key){const line=lines.find(function(l){return l.toLowerCase().startsWith(key.toLowerCase());});if(!line)return null;const neg=line.includes('-')||line.includes('(');const n=parseInt(line.slice(key.length).replace(/[^0-9]/g,''));return isNaN(n)?null:(neg?-n:n);};
      const yearLine=lines.find(function(l){return l.toLowerCase().startsWith('year:');});
      const yM=yearLine?yearLine.match(/(20\d\d|19\d\d)/):null;
      financials={turnover:getNum('Turnover:'),employees:getNum('Employees:'),netAssets:getNum('Net assets:'),profitAfterTax:getNum('Profit:'),accountsYear:yM?yM[1]:null};
    }
  }
}catch(e){}
const webResults=(webData.results||[]).slice(0,3);
const webSnippets=webResults.map(function(r){return(r.title||'')+': '+(r.content||'').substring(0,150);});
const reg=company.registered_office_address||{};
const address=[reg.address_line_1,reg.locality,reg.postal_code].filter(Boolean).join(', ');
const dirs=(officers.items||[]).filter(function(o){return!o.resigned_on;}).map(function(o){return o.name+' ('+o.officer_role+')';}).slice(0,5);
const profile={companyNumber:input.companyNumber,companyName:company.company_name||'',address:address,sicCodes:company.sic_codes||[],incorporated:company.date_of_creation||null,status:company.company_status||'',directors:dirs,customerRanking:input.ranking,products:input.products,financials:financials,webSnippets:webSnippets,profileDate:new Date().toISOString().split('T')[0]};
const store=$getWorkflowStaticData('global');
if(!store.profiles)store.profiles={};
store.profiles[input.companyNumber]=profile;
return[{json:profile}];

const store=$getWorkflowStaticData('global');
const profiles=store.profiles||{};
const list=Object.values(profiles).sort(function(a,b){return b.customerRanking-a.customerRanking;});
const date=new Date().toLocaleDateString('en-GB');
const subj='Portland Fuel Customer Profiles \u2014 '+list.length+' companies | '+date;
const ch=function(n){return 'https://find-and-update.company-information.service.gov.uk/company/'+n;};
const rows=list.map(function(p){const fin=p.financials||{};return '<tr><td style="padding:8px;border-bottom:1px solid #ddd"><strong><a href="'+ch(p.companyNumber)+'" target="_blank">'+p.companyName+'</a></strong><br><small>'+p.companyNumber+'</small></td><td style="padding:8px;border-bottom:1px solid #ddd;text-align:center"><strong>'+p.customerRanking+'/10</strong></td><td style="padding:8px;border-bottom:1px solid #ddd">'+(p.products||[]).join(', ')+'</td><td style="padding:8px;border-bottom:1px solid #ddd">'+(p.sicCodes||[]).join(', ')+'</td><td style="padding:8px;border-bottom:1px solid #ddd">'+(fin.turnover?'\u00a3'+fin.turnover.toLocaleString():'\u2014')+'</td><td style="padding:8px;border-bottom:1px solid #ddd">'+(fin.employees||'\u2014')+'</td><td style="padding:8px;border-bottom:1px solid #ddd">'+(p.profileDate||'')+'</td></tr>';}).join('');
const avgRanking=list.length?(list.reduce(function(s,p){return s+p.customerRanking;},0)/list.length).toFixed(1):'0';
const html='<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;max-width:1100px;margin:0 auto"><h2 style="color:#2c3e50">Portland Fuel Customer Profiles</h2><p><b>'+list.length+' companies</b> | Average ranking: '+avgRanking+'/10 | '+date+(list.length===0?' \u2014 No profiles saved yet.':'')+'</p><table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse"><thead><tr style="background:#2c3e50;color:#fff"><th style="padding:8px;text-align:left">Company</th><th style="padding:8px;width:60px">Rank</th><th style="padding:8px;width:180px">Products</th><th style="padding:8px;width:100px">SIC</th><th style="padding:8px;width:100px">Turnover</th><th style="padding:8px;width:80px">Employees</th><th style="padding:8px;width:90px">Profiled</th></tr></thead><tbody>'+rows+'</tbody></table><p style="color:#999;font-size:11px">Generated '+new Date().toISOString()+' via n8n / amelai</p></body></html>';
return[{json:{subject:subj,htmlBody:html}}];

const input=$('Parse Input').first().json;
const store=$getWorkflowStaticData('global');
if(!store.profiles)store.profiles={};
const existing=store.profiles[input.companyNumber];
if(!existing)return[{json:{companyNumber:input.companyNumber,companyName:'Unknown',removed:false}}];
const name=existing.companyName||input.companyNumber;
delete store.profiles[input.companyNumber];
return[{json:{companyNumber:input.companyNumber,companyName:name,removed:true}}];

const p=$input.first().json;
const date=new Date().toLocaleDateString('en-GB');
const subj=p.removed?'Profile Removed: '+p.companyName+' ('+p.companyNumber+')':'Profile Not Found: '+p.companyNumber;
const msg=p.removed?'<p>The profile for <strong>'+p.companyName+'</strong> ('+p.companyNumber+') has been removed from the customer database.</p>':'<p>No profile was found for company number <strong>'+p.companyNumber+'</strong>. Nothing was deleted.</p>';
const html='<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto"><h2 style="color:#2c3e50">'+(p.removed?'Profile Removed':'Profile Not Found')+'</h2>'+msg+'<p style="color:#999;font-size:11px">'+date+' via n8n / amelai</p></body></html>';
return[{json:{subject:subj,htmlBody:html}}];
